from fastapi import APIRouter, Depends, HTTPException
from typing import List
import models, schemas
def search_books(db: Session, title: str = None, author_name: str = None):
    query = db.query(models.Book)
    if title:
        query = query.filter(models.Book.title.ilike(f'%{title}%'))
    if author_name:
        query = query.join(models.Author).filter(models.Author.name.ilike(f'%{author_name}%'))
    return query.all()

router = APIRouter()
@router.get('/search/', response_model=List[schemas.Book])
def search(title: str = None, author_name: str = None, db: Session = Depends(get_db)):
    results = search_books(db, title=title, author_name=author_name)
    if not results:
        raise HTTPException(status_code=404, detail='No books found')
    return results

