dependencies

router = APIRouter()

def assign_task_to_user(db: Session, task_id: int, user_id: int):
    task = db.query(models.Task).filter(models.Task.id == task_id).first()
    if not task:
        raise HTTPException(status_code=404, detail="Task not found")
    user = db.query(models.User).filter(models.User.id == user_id).first()
    if not user:
        raise HTTPException(status_code=404, detail="User not found")
    task.assigned_to = user
    db.commit()
    db.refresh(task)
    return task

@router.post('/projects/{project_id}/tasks/{task_id}/assign', response_model=schemas.Task)
def assign_task(project_id: int, task_id: int, user_id: int, db: Session = Depends(dependencies.get_db)):
    project = db.query(models.Project).filter(models.Project.id == project_id).first()
    if not project:
        raise HTTPException(status_code=404, detail="Project not found")
