from fastapi import FastAPI, Depends, HTTPException
from sqlalchemy.orm import Session
from datetime import datetime
database = get_database()
app = FastAPI()

@app.post('/checkout/')
def checkout_book(book_id: int, borrower_id: int, db: Session = Depends(get_db)):
    book = crud.get_book(db, book_id)
    if not book or book.is_checked_out:
        raise HTTPException(status_code=400, detail='Book is not available for checkout.')
    borrower = crud.get_borrower(db, borrower_id)
    if not borrower:
        raise HTTPException(status_code=400, detail='Borrower does not exist.')
    transaction = Transaction(book_id=book_id, borrower_id=borrower_id, checkout_date=datetime.now())
    db.add(transaction)
    book.is_checked_out = True
    db.commit()
    return {'message': 'Book checked out successfully.'}

@app.post('/return/')
def return_book(book_id: int, db: Session = Depends(get_db)):
    transaction = crud.get_latest_transaction(db, book_id)
    if not transaction or not transaction.checkout_date:
        raise HTTPException(status_code=400, detail='Book was not checked out.')
    transaction.return_date = datetime.now()
    book = crud.get_book(db, book_id)
    book.is_checked_out = False
    db.commit()
    return {'message': 'Book returned successfully.'}

