@app.post('/register/', response_model=User)
def register(user: User, db: psycopg2.extensions.connection = Depends(get_db)):
    cursor = db.cursor()
    hashed_password = get_password_hash(user.password)
    try:
        cursor.execute(
            'INSERT INTO users (username, email, password) VALUES (%s, %s, %s)',
            (user.username, user.email, hashed_password)
        )
        db.commit()
    except psycopg2.IntegrityError as e:
        db.rollback()
        raise HTTPException(status_code=400, detail='Username or email already registered') from e
    finally:
        cursor.close()
    return user

@app.post('/login/', response_model=Token)
def login(user: User, db: psycopg2.extensions.connection = Depends(get_db)):
    cursor = db.cursor()
    try:
        cursor.execute('SELECT password FROM users WHERE username = %s', (user.username,))
        hashed_password = cursor.fetchone()
        if not hashed_password or not verify_password(user.password, hashed_password[0]):
            raise HTTPException(status_code=401, detail='Incorrect username or password')
        access_token_expires = timedelta(minutes=ACCESS_TOKEN_EXPIRE_MINUTES)
        access_token = create_access_token(
            data={'sub': user.username}, expires_delta=access_token_expires
        )
    finally:
        cursor.close()
    return {'access_token': access_token, 'token_type': 'bearer'}
